import{Ga as n,Ha as t,Ia as i,Oa as e,va as r}from"./chunk-UORZ6YHK.js";var s=class a{static \u0275fac=function(o){return new(o||a)};static \u0275cmp=r({type:a,selectors:[["app-about"]],decls:131,vars:0,consts:[[1,"page-hero","about-hero"],[1,"page-hero-content"],[1,"scroll-indicator"],[1,"chevron"],[1,"content-section"],[1,"container"],[1,"emphasis"],[1,"value-block"],["href","/images/Hope%20Covenant%20Constitution.pdf","target","_blank","rel","noopener"],[1,"leader-profile"],[1,"music-list"]],template:function(o,l){o&1&&(n(0,"section",0)(1,"div",1)(2,"h1"),e(3,"ABOUT"),i(4,"br"),e(5,"HOPE COVENANT CHURCH"),t()(),n(6,"div",2),i(7,"span",3),t()(),n(8,"section",4)(9,"div",5)(10,"p"),e(11,"We are a close community of God's people, who meet regularly to worship and study our Saviour's word. We love the Gospel of the Lord Jesus Christ through which we have been saved and are eager to share it with any who will listen! Come and join us."),t(),n(12,"p"),e(13,"So, what is important to us? It is important to us that we honour God in our worship and life as a multi-cultural community. We seek to be reverent but joyful in our prayers and songs. The Bible holds a prominent place in our hearts, because we believe ardently that it is God's infallible word and so we both teach it and regulate everything by it. We're an independent, evangelical and reformed congregation."),t(),n(14,"h2"),e(15,"Summary"),t(),n(16,"p"),e(17,"You will notice straight away that family is very important to us. We worship as families holding to the precious promises that God has made to Christians and their households. We believe that Jesus, God's Son, died and rose from the dead to save us and to restore what man originally lost in sinning against the Lord."),t(),n(18,"p"),e(19,"That means as individuals we have communion with the triune God, and as households we serve the Lord."),t(),n(20,"p",6),e(21,"We can sum up what is important to us: it is to live as God's redeemed community in service."),t(),n(22,"h2"),e(23,"But, What Does That Mean?"),t(),n(24,"h3"),e(25,"We're God's Redeemed Community..."),t(),n(26,"p"),e(27,"We believe that the church is God's possession and design. God's Son died to bring us back to Himself. God originally created us to love and worship Him and enjoy His presence but when Adam sinned rebellion, disobedience and hate for the Lord entered all our hearts. This is the root of all our troubles and broken lives. The Lord Jesus makes worshipers of us again."),t(),n(28,"p"),e(29,"We believe that the Lord Jesus died to save us as individuals and each of us has as a responsibly to seek the Lord's mercy in repentance and faith."),t(),n(30,"p"),e(31,"Jesus redeemed His people, dying at Calvary to pay for sin. He removes our guilt and sends the Holy Spirit to cleanse and change our hearts, restoring us to enjoy communion and worship of Him."),t(),n(32,"p"),e(33,"Our first great aim then must be to worship God as a multi-cultural group of people according to His commands and design. We are called to be a holy community, the word holy simply means set aside for God. Ephesians 2:14-22."),t(),n(34,"p"),e(35,"This community is made up of both individuals and families devoted to the Lord. The scriptures clearly show us that God not only changes our lives but also restores our families. The Bible is filled with instruction to husbands, wives and children. Ephesians 5:15-6:4."),t(),n(36,"h3"),e(37,"...In Service."),t(),n(38,"p"),e(39,"We believe that all Christians are given gifts by the Lord Jesus to serve. Our saviour has called us to be disciples and to obey what he has commanded us as we follow him. This means that each member is able to and called to service in the local congregation."),t(),n(40,"p"),e(41,"We also believe that everyone has an obligation to spread the gospel who are without God and without hope. Matthew 28:18-20, Ephesians 2:12-13."),t(),n(42,"p"),e(43,"We are also connected to various external mission organizations that we serve with and pray for."),t(),n(44,"h2"),e(45,"Our Core Values"),t(),n(46,"div",7)(47,"h3"),e(48,"The bible and the gospel"),t(),n(49,"p"),e(50,"We hold that, the Bible is the only, reliable, sufficient, and non-negotiable norm for learning and living. We are convinced that the Bible is focused on our Lord Jesus Christ and Him crucified. He is the only way we can worship God, with the help of the Holy Spirit."),t(),n(51,"p"),e(52,"We believe in the necessity of rebirth, repentance, sanctification, and perseverance. We also believe that gospel preaching is the power of God through which the Holy Spirit enables us to experience these things."),t()(),n(53,"div",7)(54,"h3"),e(55,"Historical context"),t(),n(56,"p"),e(57,"We agree with the historical Reformed Christians' beliefs, as laid out in the five Solas, the doctrines of grace, the regulatory principle for worship, the covenant view of God's plan of salvation, and the relevance of the Old Testament law of God to the New Testament believer. We also acknowledge the Heidelberg Catechism, the Belgic Confession, the Savoy Declaration, the Westminster Confession and the 1689 London Confession to be sound summaries of Christian belief. We are congregational. We place a high premium on the local church as an independent community of true believers."),t()(),n(58,"div",7)(59,"h3"),e(60,"Our views on baptism"),t(),n(61,"p"),e(62,`Due to the diversity of exegetical views on to the mode and time of baptism, "HCC" allows both infant and believers' baptism. Believers who hold either point of view may become members of the congregation, serve in leadership or on the council and enjoy all the privileges of church membership, provided they qualify on all other grounds required for membership and leadership. Members from different points of view are encouraged to lovingly bear with one another.`),t(),n(63,"p"),e(64,"One party will not try to coerce the other to comply or do that which their consciences do not allow. This does not exclude robust discussion on the topic to be done in a gracious biblical manner in an attempt for both parties to draw closer to the biblical truth of the matter."),t(),n(65,"p"),e(66,"For more information about us please refer to our constitution "),n(67,"a",8),e(68,"here"),t(),e(69,"."),t()(),n(70,"h2"),e(71,"Leadership"),t(),n(72,"h3"),e(73,"Leadership structure"),t(),n(74,"p"),e(75,"Our church is governed by elders, equipped by God to shepherd and oversee the work. We also have a council of deacons to assist the elders in their work with the various by overseeing the day-to-day operations. While we are an independent congregation we look to the leadership of other like-minded congregations for guidance, accountability and assistance."),t(),n(76,"h3"),e(77,"Vocational Pastor"),t(),n(78,"p"),e(79,"Michael is married to Gillian Marsland since 1986. He has served in two congregations and worked with various missions and theological colleges in training men for ministry. He has served in the ministry since 1986."),t(),n(80,"h3"),e(81,"Elders"),t(),n(82,"div",9)(83,"h4"),e(84,"ELIAS"),t(),n(85,"p"),e(86,"Elias Masango is a minister of the Gospel serving at Hope Covenant Church in Horizon, JHB, while also working at Johannesburg Bible College. He grew up in Mpumalanga, and became a Christian two decades ago. He has completed his theological degree through Makhanyo Bible College and George Whitfield College as satellites affiliated to NWU. He has been married to Nozipho since 2012 and they are blessed with three children: a daughter, Sindisiwe, a son, Theo and a daughter, Ziphezihle. He enjoys watching sport in his spare time."),t()(),n(87,"div",9)(88,"h4"),e(89,"NEIL"),t(),n(90,"p"),e(91,"Neil grew up on a farm in KwaZulu-Natal and became a christian as a teenager under the faithful teaching of his godly parents. After studying mechanical engineering in Durban, he moved to Newcastle, where he came to understand and love the doctrines of grace."),t(),n(92,"p"),e(93,"He and his wife, Felicity, moved to Roodepoort in 1998 and were founding members of Hope Covenant Church (previously Christ Church Horison) in 2002."),t(),n(94,"p"),e(95,"They have seven beautiful Children and have also been blessed with a son-in-law and a daughter-in-law."),t()(),n(96,"div",9)(97,"h4"),e(98,"IZAK"),t(),n(99,"p"),e(100,"Izak van der Walt was called to serve at Hope Covenant Church in 2026. He recently completed his full-time theological studies through the Bible Institute of South Africa (BISA) and is now serving in full-time ministry. Izak has been happily married since 2016, and considers himself extraordinarily wealthy\u2014not in material terms, but through the immense blessing of his four children. In his ministry, he deeply shares the desire of our Heavenly Father that none should perish, but that all should come to repentance, and he is dedicated to seeing the gospel transform lives in the community."),t()(),n(101,"h3"),e(102,"Deacons"),t(),n(103,"p"),e(104,"Robert has been a member of the church since 2022. He coordinates the young adult's ministry in the church. By day he is an aeronautical engineer, by night he tries to do as much rock climbing and triathlon training as he is able to. At all times he loves Jesus Christ, and wants to see more people come to know the depths of His wonderful, saving grace!"),t(),n(105,"h2"),e(106,"Music Policy"),t(),n(107,"div",7)(108,"h3"),e(109,"The Selection of Music"),t(),n(110,"p"),e(111,"We recognise the Biblical requirement to worship God with various songs and hymns during corporate worship (Ephesians 5:19, Psalm 100). We recognise the deep and rich history of ancient hymns and tunes that have been preserved through generations of Christian liturgy but also acknowledge the beautiful scriptural and doctrinal soundness of modern hymn writers."),t(),n(112,"ul",10)(113,"li")(114,"strong"),e(115,"A)"),t(),e(116," They must be theologically sound."),t(),n(117,"li")(118,"strong"),e(119,"B)"),t(),e(120," Hymns must show reverence and awe for God and we should avoid songs that are shallow, flippant, or needlessly repetitive."),t(),n(121,"li")(122,"strong"),e(123,"C)"),t(),e(124," They must reflect our joy in the Lord and in our salvation (Psalm 98:4)."),t(),n(125,"li")(126,"strong"),e(127,"D)"),t(),e(128," We all sing together to encourage one another in the Lord. The nature of the songs should be conducive for all to sing."),t()(),n(129,"p"),e(130,"We encourage our musicians to select music that best helps the congregation of our church to worship God. We recommend that the music we sing during our services takes the congregation from general affirmations, confessions, and worship of God (in the opening few hymns) to more specific and thematic hymns (at the end of the service)."),t()()()())},styles:[".about-hero[_ngcontent-%COMP%]{position:relative;background:linear-gradient(#1a1a2eb3,#0f3460bf),url(/images/about-hero.jpg) center/cover no-repeat;min-height:85vh;display:flex;align-items:center;justify-content:center;text-align:center}.page-hero-content[_ngcontent-%COMP%]   h1[_ngcontent-%COMP%]{color:#fff;font-size:3rem;letter-spacing:2px;line-height:1.15;font-weight:700}.content-section[_ngcontent-%COMP%]{padding:4rem 1.5rem}.container[_ngcontent-%COMP%]{max-width:780px;margin:0 auto}.content-section[_ngcontent-%COMP%]   h2[_ngcontent-%COMP%]{font-size:1.65rem;color:#1a1a2e;margin-top:3.5rem;margin-bottom:1rem;letter-spacing:.5px;font-weight:600}.content-section[_ngcontent-%COMP%]   h2[_ngcontent-%COMP%]:first-child{margin-top:0}.content-section[_ngcontent-%COMP%]   h3[_ngcontent-%COMP%]{font-size:1.2rem;color:#0078a7;margin-top:2rem;margin-bottom:.75rem;font-weight:600}.content-section[_ngcontent-%COMP%]   p[_ngcontent-%COMP%]{margin-bottom:1.15rem;font-size:.95rem;line-height:1.8;color:#4a5568}.emphasis[_ngcontent-%COMP%]{font-family:Playfair Display,Georgia,serif;font-size:1.15rem;color:#c9a84c;font-weight:600;padding:1.25rem 0;font-style:italic}.value-block[_ngcontent-%COMP%]{margin-bottom:1.5rem}.music-list[_ngcontent-%COMP%]{list-style:none;padding:0;margin:1.25rem 0}.music-list[_ngcontent-%COMP%]   li[_ngcontent-%COMP%]{padding:.5rem 0;font-size:.95rem;color:#4a5568;line-height:1.7}.leadership-grid[_ngcontent-%COMP%]{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:1.5rem;margin:2rem 0}.leader-profile[_ngcontent-%COMP%]{margin-top:1.5rem}.leader-profile[_ngcontent-%COMP%]   h4[_ngcontent-%COMP%]{font-family:Inter,sans-serif;font-size:1rem;font-weight:700;color:#1a1a2e;letter-spacing:.5px;margin-bottom:.5rem}.leader-profile[_ngcontent-%COMP%]   p[_ngcontent-%COMP%]{margin-bottom:.5rem;font-size:.9rem;line-height:1.8;color:#4a5568}@media(max-width:768px){.about-hero[_ngcontent-%COMP%]{min-height:55vh}.page-hero-content[_ngcontent-%COMP%]   h1[_ngcontent-%COMP%]{font-size:2rem}}"]})};export{s as AboutPage};
